import { cn } from "@/lib/utils";
import { Link } from "react-router-dom";

export function EmptyState({
  icon: Icon,
  title = "Nothing here yet",
  description,
  actions = [],
  className,
}) {
  return (
    <div
      className={cn(
        "flex flex-col items-center justify-center text-center py-16 px-6",
        className
      )}
    >
      {Icon && (
        <div className="inline-flex items-center justify-center w-14 h-14 rounded-full bg-foreground/5 border border-foreground/10 mb-5">
          <Icon className="w-7 h-7 text-foreground/40" />
        </div>
      )}
      <h3 className="font-heading text-xl font-bold tracking-tight mb-1.5">
        {title}
      </h3>
      {description && (
        <p className="text-foreground/50 text-sm max-w-md leading-relaxed mb-6">
          {description}
        </p>
      )}
      {actions.length > 0 && (
        <div className="flex items-center gap-3 flex-wrap justify-center">
          {actions.map((action, i) => {
            if (action.to) {
              return (
                <Link
                  key={i}
                  to={action.to}
                  className="inline-flex items-center gap-2 bg-emerald-500 hover:bg-emerald-400 text-black font-bold uppercase tracking-[0.18em] text-xs px-4 py-2.5 rounded-sm transition-colors"
                  onClick={action.onClick}
                >
                  {action.label}
                </Link>
              );
            }
            return (
              <button
                key={i}
                onClick={action.onClick}
                className="inline-flex items-center gap-2 bg-emerald-500 hover:bg-emerald-400 text-black font-bold uppercase tracking-[0.18em] text-xs px-4 py-2.5 rounded-sm transition-colors"
              >
                {action.label}
              </button>
            );
          })}
        </div>
      )}
    </div>
  );
}
